{"content":"import React, { useState, useEffect } from 'react';
import './App.css';
import Calendar from './components/Calendar';
import EventModal from './components/EventModal';
import { Event } from './types';

const App: React.FC = () => {
  const [events, setEvents] = useState<Event[]>([]);
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [showModal, setShowModal] = useState(false);
  const [editingEvent, setEditingEvent] = useState<Event | null>(null);

  // Load events from localStorage on mount
  useEffect(() => {
    const savedEvents = localStorage.getItem('calendar-events');
    if (savedEvents) {
      try {
        const parsedEvents = JSON.parse(savedEvents).map((event: any) => ({
          ...event,
          startDate: new Date(event.startDate),
          endDate: event.endDate ? new Date(event.endDate) : undefined,
        }));
        setEvents(parsedEvents);
      } catch (error) {
        console.error('Error loading events from localStorage:', error);
      }
    }
  }, []);

  // Save events to localStorage whenever events change
  useEffect(() => {
    localStorage.setItem('calendar-events', JSON.stringify(events));
  }, [events]);

  const handleDateClick = (date: Date) => {
    setSelectedDate(date);
    setEditingEvent(null);
    setShowModal(true);
  };

  const handleEventClick = (event: Event) => {
    setSelectedDate(event.startDate);
    setEditingEvent(event);
    setShowModal(true);
  };

  const handleSaveEvent = (eventData: Omit<Event, 'id' | 'createdBy'>) => {
    if (editingEvent) {
      // Update existing event
      setEvents(prev => prev.map(evt =>
        evt.id === editingEvent.id
          ? { ...evt, ...eventData }
          : evt
      ));
    } else {
      // Create new event
      const newEvent: Event = {
        ...eventData,
        id: Date.now().toString(),
        createdBy: 'You', // Hardcoded for single user
      };
      setEvents(prev => [...prev, newEvent]);
    }
    setShowModal(false);
    setEditingEvent(null);
  };

  const handleDeleteEvent = (eventId: string) => {
    setEvents(prev => prev.filter(evt => evt.id !== eventId));
    setShowModal(false);
    setEditingEvent(null);
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setEditingEvent(null);
  };

  return (
    <div className="app">
      <header className="app-header">
        <h1>Personal Calendar</h1>
        <p>Manage your events for the next 4 years</p>
      </header>

      <main className="app-main">
        <Calendar
          events={events}
          onDateClick={handleDateClick}
          onEventClick={handleEventClick}
        />
      </main>

      {showModal && (
        <EventModal
          selectedDate={selectedDate}
          editingEvent={editingEvent}
          onSave={handleSaveEvent}
          onDelete={handleDeleteEvent}
          onClose={handleCloseModal}
        />
      )}
    </div>
  );
};

export default App;","filePath":"/Users/BHAGARO1/code/AI-copilot-vibe-app/src/App.tsx"}

