{"content":"import React, { useState } from 'react';
import { format, startOfMonth, endOfMonth, startOfWeek, endOfWeek, addDays, isSameMonth, isSameDay, addMonths, subMonths, addWeeks, subWeeks, addYears, subYears } from 'date-fns';
import { Event, ViewMode } from '../types';
import './Calendar.css';

interface CalendarProps {
  events: Event[];
  onDateClick: (date: Date) => void;
  onEventClick: (event: Event) => void;
}

const Calendar: React.FC<CalendarProps> = ({ events, onDateClick, onEventClick }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [viewMode, setViewMode] = useState<ViewMode>('month');

  const renderHeader = () => {
    const dateFormat = viewMode === 'month' ? 'MMMM yyyy' : viewMode === 'week' ? "'Week of' MMM d, yyyy" : 'MMM d, yyyy';

    return (
      <div className="calendar-header">
        <div className="calendar-nav">
          <button onClick={prevPeriod}>&lt;</button>
          <span>{format(currentDate, dateFormat)}</span>
          <button onClick={nextPeriod}>&gt;</button>
        </div>
        <div className="view-modes">
          <button
            className={viewMode === 'month' ? 'active' : ''}
            onClick={() => setViewMode('month')}
          >
            Month
          </button>
          <button
            className={viewMode === 'week' ? 'active' : ''}
            onClick={() => setViewMode('week')}
          >
            Week
          </button>
          <button
            className={viewMode === 'day' ? 'active' : ''}
            onClick={() => setViewMode('day')}
          >
            Day
          </button>
        </div>
      </div>
    );
  };

  const prevPeriod = () => {
    if (viewMode === 'month') {
      setCurrentDate(subMonths(currentDate, 1));
    } else if (viewMode === 'week') {
      setCurrentDate(subWeeks(currentDate, 1));
    } else {
      setCurrentDate(subMonths(currentDate, 1)); // For day view, go back a month
    }
  };

  const nextPeriod = () => {
    if (viewMode === 'month') {
      setCurrentDate(addMonths(currentDate, 1));
    } else if (viewMode === 'week') {
      setCurrentDate(addWeeks(currentDate, 1));
    } else {
      setCurrentDate(addMonths(currentDate, 1)); // For day view, go forward a month
    }
  };

  const renderDaysOfWeek = () => {
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    return (
      <div className="days-of-week">
        {days.map(day => (
          <div key={day} className="day-header">{day}</div>
        ))}
      </div>
    );
  };

  const renderMonthView = () => {
    const monthStart = startOfMonth(currentDate);
    const monthEnd = endOfMonth(monthStart);
    const startDate = startOfWeek(monthStart);
    const endDate = endOfWeek(monthEnd);

    const rows = [];
    let days = [];
    let day = startDate;

    while (day <= endDate) {
      for (let i = 0; i < 7; i++) {
        const cloneDay = day;
        const dayEvents = events.filter(event =>
          isSameDay(event.startDate, day) ||
          (event.endDate && event.startDate <= day && event.endDate >= day)
        );

        days.push(
          <div
            key={day.toString()}
            className={`calendar-day ${!isSameMonth(day, monthStart) ? 'disabled' : ''} ${isSameDay(day, new Date()) ? 'today' : ''}`}
            onClick={() => onDateClick(cloneDay)}
          >
            <span className="day-number">{format(day, 'd')}</span>
            <div className="day-events">
              {dayEvents.slice(0, 3).map(event => (
                <div
                  key={event.id}
                  className="event-item"
                  onClick={(e) => {
                    e.stopPropagation();
                    onEventClick(event);
                  }}
                >
                  {event.name}
                </div>
              ))}
              {dayEvents.length > 3 && (
                <div className="more-events">+{dayEvents.length - 3} more</div>
              )}
            </div>
          </div>
        );
        day = addDays(day, 1);
      }
      rows.push(
        <div key={day.toString()} className="calendar-row">
          {days}
        </div>
      );
      days = [];
    }
    return <div className="calendar-body">{rows}</div>;
  };

  const renderWeekView = () => {
    const weekStart = startOfWeek(currentDate);
    const days = [];

    for (let i = 0; i < 7; i++) {
      const day = addDays(weekStart, i);
      const dayEvents = events.filter(event =>
        isSameDay(event.startDate, day) ||
        (event.endDate && event.startDate <= day && event.endDate >= day)
      );

      days.push(
        <div key={day.toString()} className="week-day">
          <div className="week-day-header">
            <div className="day-name">{format(day, 'EEE')}</div>
            <div className="day-date">{format(day, 'd')}</div>
          </div>
          <div className="week-day-events">
            {dayEvents.map(event => (
              <div
                key={event.id}
                className="week-event-item"
                onClick={() => onEventClick(event)}
              >
                <div className="event-time">{format(event.startDate, 'HH:mm')}</div>
                <div className="event-name">{event.name}</div>
                <div className="event-creator">by {event.createdBy}</div>
              </div>
            ))}
          </div>
        </div>
      );
    }

    return <div className="week-view">{days}</div>;
  };

  const renderDayView = () => {
    const dayEvents = events.filter(event =>
      isSameDay(event.startDate, currentDate) ||
      (event.endDate && event.startDate <= currentDate && event.endDate >= currentDate)
    );

    return (
      <div className="day-view">
        <h3>{format(currentDate, 'EEEE, MMMM d, yyyy')}</h3>
        <div className="day-events">
          {dayEvents.length === 0 ? (
            <p>No events for this day</p>
          ) : (
            dayEvents.map(event => (
              <div
                key={event.id}
                className="day-event-item"
                onClick={() => onEventClick(event)}
              >
                <div className="event-name">{event.name}</div>
                <div className="event-time">
                  {format(event.startDate, 'HH:mm')}
                  {event.endDate && ` - ${format(event.endDate, 'HH:mm')}`}
                </div>
                {event.details && <div className="event-details">{event.details}</div>}
                <div className="event-creator">Created by {event.createdBy}</div>
              </div>
            ))
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="calendar">
      {renderHeader()}
      {viewMode === 'month' && (
        <>
          {renderDaysOfWeek()}
          {renderMonthView()}
        </>
      )}
      {viewMode === 'week' && renderWeekView()}
      {viewMode === 'day' && renderDayView()}
    </div>
  );
};

export default Calendar;","filePath":"/Users/BHAGARO1/code/AI-copilot-vibe-app/src/components/Calendar.tsx"}

{"content":"import React, { useState, useEffect } from 'react';
import { format } from 'date-fns';
import { Event } from '../types';
import './EventModal.css';

interface EventModalProps {
  selectedDate: Date | null;
  editingEvent: Event | null;
  onSave: (event: Omit<Event, 'id' | 'createdBy'>) => void;
  onDelete: (eventId: string) => void;
  onClose: () => void;
}

const EventModal: React.FC<EventModalProps> = ({
  selectedDate,
  editingEvent,
  onSave,
  onDelete,
  onClose
}) => {
  const [name, setName] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [details, setDetails] = useState('');

  useEffect(() => {
    if (editingEvent) {
      setName(editingEvent.name);
      setStartDate(format(editingEvent.startDate, "yyyy-MM-dd'T'HH:mm"));
      setEndDate(editingEvent.endDate ? format(editingEvent.endDate, "yyyy-MM-dd'T'HH:mm") : '');
      setDetails(editingEvent.details || '');
    } else if (selectedDate) {
      setName('');
      setStartDate(format(selectedDate, "yyyy-MM-dd'T'HH:mm"));
      setEndDate('');
      setDetails('');
    }
  }, [editingEvent, selectedDate]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!name.trim()) {
      alert('Event name is required');
      return;
    }

    const start = new Date(startDate);
    const end = endDate ? new Date(endDate) : undefined;

    if (end && start > end) {
      alert('End date must be after start date');
      return;
    }

    onSave({
      name: name.trim(),
      startDate: start,
      endDate: end,
      details: details.trim() || undefined,
    });
  };

  const handleDelete = () => {
    if (editingEvent && window.confirm('Are you sure you want to delete this event?')) {
      onDelete(editingEvent.id);
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h2>{editingEvent ? 'Edit Event' : 'Add Event'}</h2>
          <button className="close-button" onClick={onClose}>&times;</button>
        </div>

        <form onSubmit={handleSubmit} className="event-form">
          <div className="form-group">
            <label htmlFor="event-name">Event Name *</label>
            <input
              id="event-name"
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Enter event name"
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="start-date">Start Date & Time *</label>
            <input
              id="start-date"
              type="datetime-local"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="end-date">End Date & Time (optional)</label>
            <input
              id="end-date"
              type="datetime-local"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
            />
            <small>If not provided, this will be a single-day event</small>
          </div>

          <div className="form-group">
            <label htmlFor="event-details">Event Details (optional)</label>
            <textarea
              id="event-details"
              value={details}
              onChange={(e) => setDetails(e.target.value)}
              placeholder="Enter additional details"
              rows={3}
            />
          </div>

          <div className="modal-actions">
            <button type="submit" className="save-button">
              {editingEvent ? 'Update Event' : 'Save Event'}
            </button>
            {editingEvent && (
              <button type="button" className="delete-button" onClick={handleDelete}>
                Delete Event
              </button>
            )}
            <button type="button" className="cancel-button" onClick={onClose}>
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default EventModal;","filePath":"/Users/BHAGARO1/code/AI-copilot-vibe-app/src/components/EventModal.tsx"}

